def handle_users(request, path_parts):
    """Handle user-related API requests."""
    global _user_counter

    # GET /users or POST /users
    if len(path_parts) == 1:
        if request.method == 'GET':
            # List users with optional query parameters
            limit = request.args.get('limit', 100, type=int)
            offset = request.args.get('offset', 0, type=int)
            users = list(_users_store.values())
            paginated = users[offset:offset + limit]
            return jsonify({
                'data': paginated,
                'total': len(users),
                'limit': limit,
                'offset': offset
            })

        elif request.method == 'POST':
            data = request.get_json(silent=True)
            if not data:
                response = jsonify({
                    'error': 'Bad Request',
                    'message': 'Request body must be valid JSON'
                })
                response.status_code = 400
                return response

            if 'name' not in data or 'email' not in data:
                response = jsonify({
                    'error': 'Bad Request',
                    'message': 'Fields "name" and "email" are required'
                })
                response.status_code = 400
                return response

            _user_counter += 1
            user_id = str(_user_counter)
            user = {
                'id': user_id,
                'name': data['name'],
                'email': data['email'],
                'metadata': data.get('metadata', {})
            }
            _users_store[user_id] = user
            response = jsonify({'data': user})
            response.status_code = 201
            return response

        else:
            response = jsonify({
                'error': 'Method Not Allowed',
                'message': f'Method {request.method} not allowed on /users'
            })
            response.status_code = 405
            return response

    # GET/PUT/DELETE /users/<id>
    elif len(path_parts) == 2:
        user_id = path_parts[1]

        if request.method == 'GET':
            if user_id not in _users_store:
                response = jsonify({
                    'error': 'Not Found',
                    'message': f'User "{user_id}" not found'
                })
                response.status_code = 404
                return response
            return jsonify({'data': _users_store[user_id]})

        elif request.method == 'PUT':
            data = request.get_json(silent=True)
            if not data:
                response = jsonify({
                    'error': 'Bad Request',
                    'message': 'Request body must be valid JSON'
                })
                response.status_code = 400
                return response

            if user_id not in _users_store:
                response = jsonify({
                    'error': 'Not Found',
                    'message': f'User "{user_id}" not found'
                })
                response.status_code = 404
                return response

            user = _users_store[user_id]
            user['name'] = data.get('name', user['name'])
            user['email'] = data.get('email', user['email'])
            user['metadata'] = data.get('metadata', user.get('metadata', {}))
            _users_store[user_id] = user
            return jsonify({'data': user})

        elif request.method == 'DELETE':
            if user_id not in _users_store:
                response = jsonify({
                    'error': 'Not Found',
                    'message': f'User "{user_id}" not found'
                })
                response.status_code = 404
                return response

            deleted_user = _users_store.pop(user_id)
            return jsonify({
                'message': f'User "{user_id}" deleted successfully',
                'data': deleted_user
            })

        else:
            response = jsonify({
                'error': 'Method Not Allowed',
                'message': f'Method {request.method} not allowed on /users/{user_id}'
            })
            response.status_code = 405
            return response

    else:
        response = jsonify({
            'error': 'Not Found',
            'message': 'Invalid users endpoint'
        })
        response.status_code = 404
        return response


